parameters.jsCode:
const content = $json.choices[0].message.content;

try {
  return [
    {
      json: JSON.parse(content)
    }
  ];
} catch (error) {
  throw new Error(`Failed to parse AI JSON: ${error.message}\n\nResponse:\n${content}`);
}
